#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int x;
        if (scanf("%d", &x) != 1) break;
        int d = 10 - x;
        printf("%d\n", d * d * d);
    }
    return 0;
}

